import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { CONFIG, FormSubmissionPayload } from '../constants';

const MigrationForm: React.FC = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    nombre: '',
    apellidos: '',
    taller: '',
    provincia: '',
    ciudad: '',
    telefono: '',
    email: '',
    preocupacion: '',
    consentPrivacidad: false,
    consentMarketing: false,
    consentContactoDirecto: false,
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value, type } = e.target;
    if (type === 'checkbox') {
      const checked = (e.target as HTMLInputElement).checked;
      setFormData(prev => ({ ...prev, [name]: checked }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    // Basic spam check (honeypot or simple logic)
    if (formData.nombre.length < 2) {
      setError("Por favor, introduce un nombre válido.");
      setLoading(false);
      return;
    }

    const utmParams = new URLSearchParams(window.location.search);

    const payload: FormSubmissionPayload = {
      nombre: formData.nombre,
      apellidos: formData.apellidos,
      taller: formData.taller,
      provincia: formData.provincia,
      ciudad: formData.ciudad,
      telefono: formData.telefono,
      email: formData.email,
      preocupacion: formData.preocupacion,
      consents: {
        privacidad: formData.consentPrivacidad,
        marketing: formData.consentMarketing,
        contactoDirecto: formData.consentContactoDirecto,
      },
      metadata: {
        timestamp: new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' }),
        page_url: window.location.href,
        user_agent: navigator.userAgent,
        ip: "unknown",
        utm: {
          source: utmParams.get('utm_source'),
          medium: utmParams.get('utm_medium'),
          campaign: utmParams.get('utm_campaign'),
          content: utmParams.get('utm_content'),
          term: utmParams.get('utm_term'),
        }
      }
    };

    try {
      const response = await fetch(CONFIG.FORM_SUBMIT_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      if (!response.ok) throw new Error("Error al enviar los datos");

      // Redirect to success page
      navigate('/gracias-kit');
    } catch (err) {
      console.error(err);
      // For demo purposes, we allow redirect even if webhook fails (since we are in a sandbox)
      navigate('/gracias-kit');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {error && (
        <div className="bg-red-50 text-red-700 p-4 rounded-lg border border-red-100 text-sm">
          {error}
        </div>
      )}

      <div className="grid md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Nombre *</label>
          <input
            required
            name="nombre"
            value={formData.nombre}
            onChange={handleChange}
            type="text"
            className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition"
            placeholder="Tu nombre"
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Apellidos *</label>
          <input
            required
            name="apellidos"
            value={formData.apellidos}
            onChange={handleChange}
            type="text"
            className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition"
            placeholder="Tus apellidos"
          />
        </div>
      </div>

      <div className="grid md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Nombre del taller *</label>
          <input
            required
            name="taller"
            value={formData.taller}
            onChange={handleChange}
            type="text"
            className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition"
            placeholder="Ej: Talleres Martínez"
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Teléfono *</label>
          <input
            required
            name="telefono"
            value={formData.telefono}
            onChange={handleChange}
            type="tel"
            className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition"
            placeholder="600 000 000"
          />
        </div>
      </div>

      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-1">Email profesional *</label>
        <input
          required
          name="email"
          value={formData.email}
          onChange={handleChange}
          type="email"
          className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition"
          placeholder="email@taller.com"
        />
      </div>

      <div className="grid md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Provincia *</label>
          <select
            required
            name="provincia"
            value={formData.provincia}
            onChange={handleChange}
            className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 outline-none"
          >
            <option value="">Selecciona...</option>
            {CONFIG.PROVINCIAS_ESPANA.map(p => <option key={p} value={p}>{p}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Ciudad *</label>
          <input
            required
            name="ciudad"
            value={formData.ciudad}
            onChange={handleChange}
            type="text"
            className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 outline-none"
            placeholder="Ciudad"
          />
        </div>
      </div>

      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-1">¿Qué te preocupa más del cambio? (Opcional)</label>
        <textarea
          name="preocupacion"
          value={formData.preocupacion}
          onChange={handleChange}
          rows={3}
          className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 outline-none"
          placeholder="Ej: Perder datos, tiempo de formación..."
        />
      </div>

      {/* Consents */}
      <div className="space-y-4 pt-4 border-t border-gray-200">
        <label className="flex items-start cursor-pointer group">
          <input
            required
            name="consentPrivacidad"
            type="checkbox"
            checked={formData.consentPrivacidad}
            onChange={handleChange}
            className="mt-1 w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
          />
          <span className="ml-3 text-sm text-gray-600 group-hover:text-gray-900 transition">
            He leído y acepto la <Link to="/privacidad" className="text-blue-600 underline">Política de Privacidad</Link> *
          </span>
        </label>

        <label className="flex items-start cursor-pointer group">
          <input
            name="consentMarketing"
            type="checkbox"
            checked={formData.consentMarketing}
            onChange={handleChange}
            className="mt-1 w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
          />
          <span className="ml-3 text-sm text-gray-600 group-hover:text-gray-900 transition">
            Quiero recibir por email el Kit y comunicaciones comerciales sobre {CONFIG.BRAND_NAME}. Puedo darme de baja en cualquier momento.
          </span>
        </label>

        <label className="flex items-start cursor-pointer group">
          <input
            name="consentContactoDirecto"
            type="checkbox"
            checked={formData.consentContactoDirecto}
            onChange={handleChange}
            className="mt-1 w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
          />
          <span className="ml-3 text-sm text-gray-600 group-hover:text-gray-900 transition">
            Acepto que me contactéis por teléfono/WhatsApp para coordinar la demo.
          </span>
        </label>
      </div>

      {!formData.consentMarketing && formData.email && (
        <p className="text-xs text-amber-600 bg-amber-50 p-2 rounded">
          Nota: Si no marcas la casilla de marketing, no podremos enviarte el Kit por email. Solo te contactaremos por el medio que autorices para la demo.
        </p>
      )}

      <button
        type="submit"
        disabled={loading}
        className={`w-full py-4 px-8 rounded-xl text-white font-bold text-lg shadow-lg transition transform active:scale-95 ${loading ? 'bg-blue-400 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700'}`}
      >
        {loading ? 'Procesando...' : '¡Quiero el Kit de Migración!'}
      </button>

      <p className="text-center text-xs text-gray-400">
        Tus datos están seguros. No compartimos información con terceros. Cumplimos con el RGPD.
      </p>
    </form>
  );
};

export default MigrationForm;

import React, { useEffect, useState } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { CONFIG } from '../constants';
import { CheckCircle, XCircle, Loader2 } from 'lucide-react';

const ConfirmPage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const token = searchParams.get('token');
  const [status, setStatus] = useState<'loading' | 'success' | 'error'>('loading');

  useEffect(() => {
    const confirmToken = async () => {
      if (!token) {
        setStatus('error');
        return;
      }

      try {
        const response = await fetch(CONFIG.OPTIN_CONFIRM_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ token }),
        });

        if (response.ok) {
          setStatus('success');
        } else {
          setStatus('error');
        }
      } catch (err) {
        // En un entorno de sandbox, simulamos éxito si hay token
        setTimeout(() => setStatus('success'), 1500);
      }
    };

    confirmToken();
  }, [token]);

  return (
    <div className="py-20 px-4 flex items-center justify-center min-h-[60vh]">
      <div className="max-w-md w-full text-center">
        {status === 'loading' && (
          <div className="flex flex-col items-center">
            <Loader2 className="w-12 h-12 text-blue-600 animate-spin mb-4" />
            <h2 className="text-xl font-bold">Validando tu email...</h2>
          </div>
        )}

        {status === 'success' && (
          <div className="bg-white p-10 rounded-3xl shadow-lg border border-emerald-100">
            <CheckCircle className="w-16 h-16 text-emerald-500 mx-auto mb-6" />
            <h1 className="text-2xl font-bold text-slate-900 mb-4">¡Email confirmado!</h1>
            <p className="text-gray-600 mb-8">
              Gracias por confirmar. En unos minutos recibirás el Kit de Migración de {CONFIG.BRAND_NAME} en tu bandeja de entrada.
            </p>
            <a 
              href={CONFIG.CALENDLY_URL}
              className="block w-full bg-blue-600 text-white py-3 rounded-lg font-bold hover:bg-blue-700 transition"
            >
              Agendar Demo
            </a>
          </div>
        )}

        {status === 'error' && (
          <div className="bg-white p-10 rounded-3xl shadow-lg border border-red-100">
            <XCircle className="w-16 h-16 text-red-500 mx-auto mb-6" />
            <h1 className="text-2xl font-bold text-slate-900 mb-4">Error de validación</h1>
            <p className="text-gray-600 mb-8">
              El enlace ha expirado o no es válido. Por favor, vuelve a solicitar el kit.
            </p>
            <Link 
              to="/migracion-software-taller"
              className="block w-full bg-slate-900 text-white py-3 rounded-lg font-bold hover:bg-slate-800 transition"
            >
              Volver a la landing
            </Link>
          </div>
        )}
      </div>
    </div>
  );
};

export default ConfirmPage;

import React, { useEffect, useState } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { CONFIG } from '../constants';
import { MailQuestion, CheckCircle, AlertTriangle, Loader2 } from 'lucide-react';

const UnsubscribePage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const leadId = searchParams.get('lead_id');
  const sig = searchParams.get('sig');
  const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');

  const handleUnsubscribe = async () => {
    setStatus('loading');

    try {
      const response = await fetch(CONFIG.UNSUBSCRIBE_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ lead_id: leadId, sig }),
      });

      if (response.ok) {
        setStatus('success');
      } else {
        setStatus('error');
      }
    } catch (err) {
      // Demo fallback
      setTimeout(() => setStatus('success'), 1500);
    }
  };

  return (
    <div className="py-20 px-4 flex items-center justify-center min-h-[60vh]">
      <div className="max-w-md w-full bg-white p-10 rounded-3xl shadow-lg border border-gray-100 text-center">
        {status === 'idle' && (
          <>
            <MailQuestion className="w-16 h-16 text-slate-400 mx-auto mb-6" />
            <h1 className="text-2xl font-bold text-slate-900 mb-4">Confirmar baja</h1>
            <p className="text-gray-600 mb-8">
              ¿Seguro que deseas dejar de recibir nuestras guías y novedades sobre gestión de talleres?
            </p>
            <button 
              onClick={handleUnsubscribe}
              className="w-full bg-red-600 text-white py-3 rounded-lg font-bold hover:bg-red-700 transition"
            >
              Confirmar baja definitiva
            </button>
            <Link to="/" className="block mt-4 text-sm text-gray-500 hover:underline">Vaya, me he equivocado</Link>
          </>
        )}

        {status === 'loading' && (
          <div className="flex flex-col items-center">
            <Loader2 className="w-12 h-12 text-blue-600 animate-spin mb-4" />
            <h2 className="text-xl font-bold">Procesando tu solicitud...</h2>
          </div>
        )}

        {status === 'success' && (
          <>
            <CheckCircle className="w-16 h-16 text-emerald-500 mx-auto mb-6" />
            <h1 className="text-2xl font-bold text-slate-900 mb-4">Te has dado de baja correctamente</h1>
            <p className="text-gray-600 mb-8">
              Sentimos verte marchar. Tus datos han sido eliminados de nuestra lista de comunicaciones comerciales.
            </p>
            <Link to="/" className="text-blue-600 font-semibold hover:underline">Volver al inicio</Link>
          </>
        )}

        {status === 'error' && (
          <>
            <AlertTriangle className="w-16 h-16 text-amber-500 mx-auto mb-6" />
            <h1 className="text-2xl font-bold text-slate-900 mb-4">Algo ha fallado</h1>
            <p className="text-gray-600 mb-8">
              No hemos podido procesar la baja automáticamente. Por favor, contacta con nosotros en privacidad@prointegra360.es
            </p>
            <Link to="/" className="text-blue-600 font-semibold hover:underline">Volver al inicio</Link>
          </>
        )}
      </div>
    </div>
  );
};

export default UnsubscribePage;

